const input = $input.first().json || {};

const chatId =
  input.chat_id ||
  input.message?.chat?.id ||
  input.callback_query?.message?.chat?.id ||
  input.callback_query?.from?.id ||
  input.message?.from?.id ||
  null;

const userId =
  input.user_id ||
  input.message?.from?.id ||
  input.callback_query?.from?.id ||
  chatId;

const plan = input.plan || 'free';
const limit = Number(input.hourly_limit || 10);
const used = Number(input.used_last_hour || 0);
const remainingRaw = input.remaining_last_hour;
const isUnlimited =
  input.is_unlimited === true ||
  input.is_unlimited === 'true';

const DISPLAY_TIME_ZONE = 'Asia/Jerusalem';

function formatReset(value) {
  if (!value) return 'about 1 hour';

  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return 'about 1 hour';
  }

  return new Intl.DateTimeFormat('en-GB', {
    timeZone: DISPLAY_TIME_ZONE,
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).format(date);
}

const remaining = Math.max(Number(remainingRaw || 0), 0);

const quotaLine = isUnlimited
  ? `AI requests: ${used}/∞ used in the last hour`
  : `AI requests: ${used}/${limit} used in the last hour, ${remaining} left`;

const resetLine = isUnlimited
  ? ''
  : `Limit resets around: ${formatReset(input.reset_at)}`;

const text =
`👋 Memoraq saves and finds your important Telegram memories.

Send me text, photos, PDFs, files, voice messages, or locations.

Commands:
/search — find saved messages
/keywords — show all keywords
/help — show help

Search logic:
• 1–2 words: quick search without AI
• 3+ words: AI semantic search
• voice/photo/document as search query: AI extracts keywords first

AI usage:
${quotaLine}
Plan: ${plan}
${resetLine}

Free users: 10 AI requests per hour.

What counts as an AI request:
• message/photo/document analysis
• AI semantic search
• voice query transcription
• media query analysis

After analysis choose:
✅ Save
🧠 AI brief
➕ Add keywords
❌ Cancel`;

return [
  {
    json: {
      user_id: userId,
      chat_id: chatId,
      text
    }
  }
];
